using System.Collections.Generic;
using UnityEngine;

/// <summary>
/// Ataque básico do player (P4): hitbox frontal que causa dano aos inimigos
/// via EnemyHealth.TakeDamage(dano, AnimalCategory, origem, knockback) —
/// aplicando automaticamente as fraquezas por categoria do Enemy Creator
/// (GDD 12.1: "dano depende da força do animal").
///
/// Parâmetros vêm da forma actual (AnimalFormData — P1): canAttack (nem todos
/// os animais atacam), attackDamage (fichas 1-10), attackRange,
/// attackKnockback, attackCooldown, categories. A animação fica por conta do
/// Animator (trigger "Attack").
///
/// Também interage com o mundo: quebra BreakableObject (conforme as flags
/// canBreak* da forma) e activa switches/alvos (IProjectileActivatable).
///
/// Dano durante investidas: com "damageWhileDashing" (ex: Charge do Elefante,
/// investida da Orca), enquanto motor.IsDashing o corpo do player fere
/// inimigos em contacto (os i-frames do inimigo evitam multi-hit).
///
/// Tarefa #30 — Hit via Animation Event + buffer de ataque + HitContext:
/// TryAttack()/PerformStrike() já não aplicam o golpe de imediato — só
/// calculam o "HitContext" (centro/tamanho da hitbox, dano, knockback,
/// breakObjects a partir da forma/direcção actuais), guardam-no como golpe
/// pendente e disparam o trigger "Attack" do Animator. O dano só é aplicado
/// quando a animação chama <see cref="AnimEvent_Hit"/> (Animation Event no
/// frame em que as garras/dentes acertam), garantindo que o impacto visual e
/// o dano coincidem.
///
/// Buffer de ataque: se o botão for premido durante o cooldown, fica
/// guardado 1 pedido (<see cref="_attackBuffered"/>); assim que o cooldown
/// terminar — e o player ainda puder atacar — o ataque dispara
/// automaticamente, sem precisar de premir de novo.
/// </summary>
[RequireComponent(typeof(PlayerMotor2D))]
public class PlayerAttack : MonoBehaviour, IFormAbility
{
    [Header("Hitbox")]
    [Tooltip("Altura da hitbox frontal (a largura vem de attackRange da forma).")]
    public float hitboxHeight = 1f;

    [Tooltip("Camadas atingíveis. Vazio = todas.")]
    public LayerMask hitMask = ~0;

    [Header("Dano em Investida (Charge/Dash ofensivos)")]
    [Tooltip("Enquanto motor.IsDashing, o corpo do player fere inimigos em contacto (raio 'dashHitRadius'). Só com canAttack na forma.")]
    public bool damageWhileDashing = true;

    public float dashHitRadius = 0.7f;

    /// <summary>Disparado quando um ataque acerta pelo menos um alvo (inimigo, objecto destrutível ou activável) — usado por PlayerFeedback (Tarefa #29) para VFX/SFX/vibração de impacto. "hitPoint" é o centro da hitbox/área do golpe.</summary>
    public event System.Action<Vector2> OnHitLanded;

    private PlayerMotor2D _motor;
    private AnimalFormData _form;
    private float _cooldownTimer;

    /// <summary>Tarefa #30 — buffer de ataque: true se o botão foi premido durante o cooldown; consumido (e disparado) assim que o cooldown terminar.</summary>
    private bool _attackBuffered;

    /// <summary>Tarefa #30 — HitContext do golpe em curso, calculado em TryAttack/PerformStrike e aplicado em AnimEvent_Hit().</summary>
    private struct HitContext
    {
        public Vector2 center;
        public Vector2 size;
        public int damage;
        public float knockback;
        public bool breakObjects;
    }

    private HitContext _pendingHit;
    private bool _hasPendingHit;

    // Buffers reutilizáveis para evitar alocações por ataque (OverlapBoxAll/OverlapCircleAll
    // alocam um array novo a cada chamada).
    private const int MaxHits = 16;
    private readonly Collider2D[] _hitBuffer = new Collider2D[MaxHits];
    private readonly HashSet<EnemyHealth> _hitEnemiesScratch = new HashSet<EnemyHealth>();

    private void Awake()
    {
        _motor = GetComponent<PlayerMotor2D>();
    }

    public void ConfigureFromForm(AnimalFormData form)
    {
        _form = form;
        _cooldownTimer = 0f;
        _attackBuffered = false;
        _hasPendingHit = false;
    }

    private void Update()
    {
        if (_cooldownTimer <= 0f) return;

        _cooldownTimer -= Time.deltaTime;

        // Buffer de ataque: assim que o cooldown terminar, dispara o ataque
        // guardado automaticamente (se ainda fizer sentido — TryAttack volta
        // a validar canAttack/MovementLocked).
        if (_cooldownTimer <= 0f && _attackBuffered)
        {
            _attackBuffered = false;
            TryAttack();
        }
    }

    private void FixedUpdate()
    {
        if (!damageWhileDashing || _form == null || !_form.canAttack) return;
        if (!_motor.IsDashing) return;
        if (IsInvisible) return;

        // Dano de contacto durante investidas (i-frames do inimigo evitam spam).
        HitArea(transform.position, dashHitRadius, _form.attackDamage, _form.attackKnockback, breakObjects: true);
    }

    /// <summary>
    /// True enquanto a invisibilidade do Pó Dourado estiver activa (GDD: "enquanto
    /// invisível, o jogador não causa dano"). Consultado por TryAttack,
    /// PerformStrike (HeavyStrike/Roar/etc. via PlayerAttack) e pelo dano de
    /// contacto em investidas (FixedUpdate).
    /// </summary>
    private bool IsInvisible => PlayerConsumableEffects.Instance != null && PlayerConsumableEffects.Instance.IsInvisible;

    /// <summary>
    /// Chamado pelo AbilityRouter no botão de ataque. Se o ataque puder
    /// começar já, dispara o trigger "Attack" e prepara o HitContext
    /// (aplicado depois em <see cref="AnimEvent_Hit"/>) — devolve true. Se o
    /// ataque básico ainda estiver em cooldown, guarda o pedido no buffer
    /// (1 ataque, disparado automaticamente quando o cooldown terminar) e
    /// devolve false. Se canAttack for false ou o movimento estiver
    /// bloqueado (fora de dash), não faz nada e devolve false.
    /// </summary>
    public bool TryAttack()
    {
        if (_form == null || !_form.canAttack) return false;
        if (_motor.MovementLocked && !_motor.IsDashing) return false;
        if (IsInvisible) return false;

        if (_cooldownTimer > 0f)
        {
            _attackBuffered = true;
            return false;
        }

        QueueHit(_form.attackDamage, _form.attackRange, _form.attackKnockback, breakObjects: true);
        _cooldownTimer = Mathf.Max(0.05f, _form.attackCooldown);

        return true;
    }

    /// <summary>
    /// Golpe avulso com parâmetros próprios (usado por HeavyStrikeAbility —
    /// Urso Polar). Ignora o cooldown do ataque básico — só dispara o
    /// trigger "Attack" e prepara o HitContext, aplicado em
    /// <see cref="AnimEvent_Hit"/> tal como o ataque básico.
    /// </summary>
    public bool PerformStrike(int damage, float range, float knockback, bool breakObjects)
    {
        if (IsInvisible) return false;

        QueueHit(damage, range, knockback, breakObjects);
        return true;
    }

    /// <summary>
    /// Calcula o HitContext (centro/tamanho da hitbox a partir da posição e
    /// direcção actuais do player) e dispara o trigger "Attack" do Animator.
    /// O golpe em si só é aplicado em <see cref="AnimEvent_Hit"/>.
    /// </summary>
    private void QueueHit(int damage, float range, float knockback, bool breakObjects)
    {
        int dir = _motor.FacingSign != 0 ? _motor.FacingSign : 1;
        Vector2 center = (Vector2)transform.position + new Vector2(dir * range * 0.5f, 0f);
        Vector2 size = new Vector2(range, hitboxHeight);

        _pendingHit = new HitContext
        {
            center = center,
            size = size,
            damage = damage,
            knockback = knockback,
            breakObjects = breakObjects
        };
        _hasPendingHit = true;

        var anim = _motor.Anim;
        if (anim != null) anim.SetTrigger("Attack");
    }

    /// <summary>
    /// Tarefa #30 — Animation Event: chamado pelo clip "Attack" do Animator
    /// no frame em que o golpe (garras/dentes/etc) acerta. Aplica o
    /// HitContext calculado em TryAttack/PerformStrike. Sem efeito se não
    /// houver golpe pendente (ex: anim event configurado num clip que não
    /// corresponde a um ataque iniciado por este script).
    /// </summary>
    public void AnimEvent_Hit()
    {
        if (!_hasPendingHit) return;
        _hasPendingHit = false;

        HitBox(_pendingHit.center, _pendingHit.size, _pendingHit.damage, _pendingHit.knockback, _pendingHit.breakObjects);
    }

    private bool HitBox(Vector2 center, Vector2 size, int damage, float knockback, bool breakObjects)
    {
        int count = Physics2D.OverlapBoxNonAlloc(center, size, 0f, _hitBuffer, hitMask);
        return ApplyHits(_hitBuffer, count, damage, knockback, breakObjects, center);
    }

    private bool HitArea(Vector2 center, float radius, int damage, float knockback, bool breakObjects)
    {
        int count = Physics2D.OverlapCircleNonAlloc(center, radius, _hitBuffer, hitMask);
        return ApplyHits(_hitBuffer, count, damage, knockback, breakObjects, center);
    }

    /// <summary>
    /// Aplica os efeitos de um golpe aos primeiros "count" elementos de "hits"
    /// (preenchidos por OverlapXNonAlloc, sem alocar array novo). Usa
    /// "_hitEnemiesScratch" para garantir que cada EnemyHealth só é atingido
    /// uma vez por golpe, mesmo que o inimigo tenha vários colliders no
    /// hitMask (ex: corpo + cabeça). Dispara <see cref="OnHitLanded"/> em
    /// "hitPoint" se pelo menos um alvo for atingido.
    /// </summary>
    private bool ApplyHits(Collider2D[] hits, int count, int damage, float knockback, bool breakObjects, Vector2 hitPoint)
    {
        bool any = false;
        _hitEnemiesScratch.Clear();

        for (int i = 0; i < count; i++)
        {
            var hit = hits[i];
            if (hit == null || hit.gameObject == gameObject) continue;

            // Inimigos: dano com categoria da forma (fraquezas — Enemy Creator).
            // Procura no pai porque os colliders de hit podem estar em filhos
            // (ex: cabeça/membros separados do corpo principal do inimigo).
            var enemyHealth = hit.GetComponentInParent<EnemyHealth>();
            if (enemyHealth != null)
            {
                // Evita atingir o mesmo inimigo 2x no mesmo golpe (múltiplos colliders).
                if (!_hitEnemiesScratch.Add(enemyHealth)) continue;

                var categories = _form != null ? _form.categories : AnimalCategory.None;
                if (enemyHealth.TakeDamage(damage, categories, transform.position, knockback))
                    any = true;
                continue;
            }

            if (!breakObjects) continue;

            // Objectos destrutíveis (P6 — madeira/gelo/rachadas conforme a forma).
            var breakable = hit.GetComponent<BreakableObject>();
            if (breakable != null)
            {
                if (breakable.TryBreakByForm(_form)) any = true;
                continue;
            }

            // Switches/alvos activáveis por ataque.
            var activatable = hit.GetComponent<IProjectileActivatable>();
            if (activatable != null)
            {
                activatable.ActivateByProjectile(null);
                any = true;
            }
        }

        if (any) OnHitLanded?.Invoke(hitPoint);

        return any;
    }
}
